class Solution {
    public boolean isLongPressedName(String name, String typed) {
        Map<Character, Integer> nameCount = new HashMap<>();
        Map<Character, Integer> typedCount = new HashMap<>();

        for (char c : name.toCharArray()) {
            nameCount.put(c, nameCount.getOrDefault(c, 0) + 1);
        }

        for (char c : typed.toCharArray()) {
            typedCount.put(c, typedCount.getOrDefault(c, 0) + 1);
        }

        for (Map.Entry<Character, Integer> entry : nameCount.entrySet()) {
            if (typedCount.containsKey(entry.getKey()) && typedCount.get(entry.getKey()) > 1) {
                return true;
            }
        }

        return false;
    }
}
